import React, { useState } from "react";

export default function Wallet({ account, setAccount }) {
  const [loading, setLoading] = useState(false);

  const connect = async () => {
    try {
      setLoading(true);
      if (!window.ethereum) {
        alert("MetaMask is not installed. Please install it from metamask.io");
        return;
      }
      const accounts = await window.ethereum.request({ method: "eth_requestAccounts" });
      setAccount(accounts[0]);
    } catch (err) {
      console.error("Wallet connect failed:", err);
    } finally {
      setLoading(false);
    }
  };

  const disconnect = () => setAccount(null);

  return (
    <div className="wallet-bar">
      {account ? (
        <div className="wallet-connected">
          <span className="wallet-dot" />
          <span className="wallet-addr">
            {account.slice(0, 6)}...{account.slice(-4)}
          </span>
          <button className="btn-disconnect" onClick={disconnect}>Disconnect</button>
        </div>
      ) : (
        <button className="btn-connect" onClick={connect} disabled={loading}>
          {loading ? "Connecting..." : "🦊 Connect Wallet"}
        </button>
      )}
    </div>
  );
}
